sql:
SELECT COUNT(DISTINCT pac_id) AS active_pacs_count
FROM pacs
WHERE status = 'Active';

external_knowledge:
Generous donors: refers to donors who contribute more than $100; 
Substantial financial support: refers to total contributions exceeding $5000; 
Active or unregistered: refers to PACs that are either 'Active' or have a NULL status.

